package dev.yazidcv.candidate;
import dev.yazidcv.job.*;import org.junit.jupiter.api.Test;import java.util.*;import static org.assertj.core.api.Assertions.assertThat;import static org.mockito.Mockito.*;
class JobMatchScoringServiceTest{
 @Test void scoresAndRanksEveryOpenJobFromExplainableEvidence(){UUID org=UUID.randomUUID();var candidate=new Candidate(org,"Samira","Example");candidate.update("Samira","Example","samira@example.test",null,"Senior Backend Engineer",null,"Casablanca","Morocco",6,"NEW","",List.of("Java","Spring Boot","React"));var backend=new JobOpening(org,"Senior Java Engineer");backend.update("Senior Java Engineer","Platform","Casablanca","HYBRID","",List.of("Java","Spring Boot","Kafka"),"OPEN",null);var frontend=new JobOpening(org,"Frontend Engineer");frontend.update("Frontend Engineer","Product","Paris","ONSITE","",List.of("React","TypeScript"),"OPEN",null);var repo=mock(JobRepository.class);when(repo.findAllByOrganizationIdAndStatusOrderByUpdatedAtDesc(org,"OPEN")).thenReturn(List.of(frontend,backend));var matches=new JobMatchScoringService(repo).scoreAll(candidate);assertThat(matches).hasSize(2);assertThat(matches.getFirst().jobTitle()).isEqualTo("Senior Java Engineer");assertThat(matches.getFirst().score()).isEqualTo(57);assertThat(matches.getFirst().matchedSkills()).containsExactly("Java","Spring Boot");assertThat(matches.getFirst().missingSkills()).containsExactly("Kafka");assertThat(matches.get(1).score()).isEqualTo(35);}
}
